patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..5e489ee9ce6c 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1132,11 +1132,13 @@ void State::addInfoFor(BasicBlock &BB) {
     case Intrinsic::umax:
     case Intrinsic::smin:
     case Intrinsic::smax:
-      // TODO: handle llvm.abs as well
+    case Intrinsic::usub_sat:
       WorkList.push_back(
           FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
       // TODO: Check if it is possible to instead only added the min/max facts
       // when simplifying uses of the min/max intrinsics.
+      if (!isGuaranteedNotToBePoison(&I))
+        break;
       if (!isGuaranteedNotToBePoison(&I))
         break;
       [[fallthrough]];
@@ -1149,7 +1151,6 @@ void State::addInfoFor(BasicBlock &BB) {
   }

   if (auto *Switch = dyn_cast<SwitchInst>(BB.getTerminator())) {
-    for (auto &Case : Switch->cases()) {
       BasicBlock *Succ = Case.getCaseSuccessor();
       Value *V = Case.getCaseValue();
       if (!canAddSuccessor(BB, Succ))
@@ -1898,6 +1899,15 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
         AddFact(Pred, MinMax, MinMax->getRHS());
         continue;
       }
+
+      // usub.sat(X, Y) returns 0 if X < Y, otherwise X - Y.
+      // In both cases, the result is <= X.
+      Value *Op0, *Op1;
+      if (match(CB.Inst, m_Intrinsic<Intrinsic::usub_sat>(m_Value(Op0),
+                                                          m_Value(Op1)))) {
+        AddFact(CmpInst::ICMP_ULE, CB.Inst, Op0);
+        continue;
+      }
     }

     Value *A = nullptr, *B = nullptr;

